                }

                return File(fileBytes, contentType, filename);
            }
            catch (UnauthorizedAccessException)
            {
                return StatusCode(403, "Access denied");
            }
            catch (IOException ex)
            {
                return StatusCode(500, $"Error reading file: {ex.Message}");
            }
        }

